USE ebs_db; -- 1. Drop the table if it exists so you can safely re-run this script DROP TABLE IF EXISTS complaints; -- 2. Create the complaints table CREATE TABLE complaints ( id BIGINT AUTO_INCREMENT PRIMARY KEY, booking_id BIGINT NOT NULL, category VARCHAR(50) NOT NULL, description TEXT NOT NULL, status VARCHAR(20) DEFAULT 'Pending', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, -- Links this complaint directly to the specific booking FOREIGN KEY (booking_id) REFERENCES bookings(id) ON DELETE CASCADE ); -- 3. (Optional) Insert some test data to verify it works right away -- Note: Make sure the booking_id '1' actually exists in your bookings table! INSERT INTO complaints (booking_id, category, description, status) VALUES (1, 'Hardware', 'The monitor keeps flickering every 5 minutes.', 'Pending'), (1, 'Network', 'Cannot connect to the university Wi-Fi on this machine.', 'Resolved');